1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	
10	const DEDUCTIBLE = 100;
11	const CAP_MULTIPLIER = 2;
12	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
13	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
14	
15	const PROCESSING_FEE = 5;
16	const FIRST_INSURANCE_SURCHARGE = 0.1;
17	const CURSE_SURCHARGE = 0.5;
18	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	const LOYALTY_DISCOUNT = 0.2;
21	const LOYALTY_YEARS_THRESHOLD = 2;
22	const FOLLOWUP_DISCOUNT = 0.15;
23	const COMPONENT_BASE_PREMIUM = 25;
24	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_INSURANCE_VALUE = 250;
27	
28	type Tariff = { base: number; insurance: number };
29	
30	const MAIN_ITEM_TARIFF: Record<string, Tariff> = {
31	  sword: { base: 100, insurance: 1000 },
32	  amulet: { base: 60, insurance: 600 },
33	};
34	
35	const isMainItem = (item: Item): boolean => item.type in MAIN_ITEM_TARIFF;
36	
37	const itemInsuranceValue = (item: Item): number =>
38	  MAIN_ITEM_TARIFF[item.type]?.insurance ?? COMPONENT_INSURANCE_VALUE;
39	
40	const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);
41	
42	const sumBy = <T>(items: T[], valueOf: (item: T) => number): number =>
43	  items.reduce((sum, item) => sum + valueOf(item), 0);
44	
45	const rateAmount = (base: number, applies: boolean, rate: number): number =>
46	  applies ? base * rate : 0;
47	
48	const isHighlyEnchanted = (item: Item): boolean =>
49	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
50	
51	const mainItemBase = (item: Item): number => MAIN_ITEM_TARIFF[item.type].base;
52	
53	const mainItemSurcharges = (item: Item): number => {
54	  const base = mainItemBase(item);
55	  return (
56	    rateAmount(base, item.cursed === true, CURSE_SURCHARGE) +
57	    rateAmount(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE)
58	  );
59	};
60	
61	const componentGroupBase = (count: number): number => {
62	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
63	  const leftover = count % COMPONENT_BLOCK_SIZE;
64	  return blocks * COMPONENT_BLOCK_BASE_PREMIUM + leftover * COMPONENT_BASE_PREMIUM;
65	};
66	
67	const componentCountsByType = (components: Item[]): Map<string, number> => {
68	  const counts = new Map<string, number>();
69	  for (const item of components) {
70	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
71	  }
72	  return counts;
73	};
74	
75	const sumComponentGroupBases = (components: Item[]): number =>
76	  sumBy([...componentCountsByType(components).values()], componentGroupBase);
77	
78	const partitionItems = (items: Item[]): { mainItems: Item[]; components: Item[] } => {
79	  const mainItems: Item[] = [];
80	  const components: Item[] = [];
81	  for (const item of items) {
82	    (isMainItem(item) ? mainItems : components).push(item);
83	  }
84	  return { mainItems, components };
85	};
86	
87	const sumMainItemBases = (mainItems: Item[]): number => sumBy(mainItems, mainItemBase);
88	
89	const sumMainItemSurcharges = (mainItems: Item[]): number => sumBy(mainItems, mainItemSurcharges);
90	
91	const isLoyalCustomer = (customer: Customer): boolean =>
92	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
93	
94	const totalDiscount = (policyBase: number, customer: Customer, isFollowUp: boolean): number =>
95	  rateAmount(policyBase, isLoyalCustomer(customer), LOYALTY_DISCOUNT) +
96	  rateAmount(policyBase, isFollowUp, FOLLOWUP_DISCOUNT);
97	
98	const priceQuote = (step: QuoteStep, customer: Customer, isFollowUp: boolean): { premium: number } => {
99	  const { mainItems, components } = partitionItems(step.items);
100	  const policyBase = sumMainItemBases(mainItems) + sumComponentGroupBases(components);
101	  const surcharges = sumMainItemSurcharges(mainItems);
102	  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
103	  const discounts = totalDiscount(policyBase, customer, isFollowUp);
104	  return {
105	    premium: ceilWithEpsilon(policyBase + surcharges + firstInsurance - discounts + PROCESSING_FEE),
106	  };
107	};
108	
109	const countQuotesBefore = (steps: Step[], index: number): number =>
110	  steps.slice(0, index).filter((s) => s.op === "quote").length;
111	
112	const insuranceSumOf = (step: QuoteStep): number => sumBy(step.items, itemInsuranceValue);
113	
114	const findInsuredItem = (policyStep: QuoteStep, itemType: string): Item | undefined =>
115	  policyStep.items.find((item) => item.type === itemType);
116	
117	const qualifiesForReducedReimbursement = (item: Item | undefined): boolean =>
118	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
119	
120	const reimbursementRate = (item: Item | undefined): number =>
121	  qualifiesForReducedReimbursement(item) ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE : 1;
122	
123	const damagePayout = (damage: Damage, policyStep: QuoteStep): number => {
124	  const item = findInsuredItem(policyStep, damage.itemType);
125	  return Math.max(0, damage.amount * reimbursementRate(item) - DEDUCTIBLE);
126	};
127	
128	const totalPayout = (damages: Damage[], policyStep: QuoteStep): number =>
129	  sumBy(damages, (d) => damagePayout(d, policyStep));
130	
131	const processClaim = (step: ClaimStep, steps: Step[]): { payout: number; remainingCap: number } => {
132	  const policyStep = steps[step.policy] as QuoteStep;
133	  const cap = CAP_MULTIPLIER * insuranceSumOf(policyStep);
134	  const payout = totalPayout(step.incident.damages, policyStep);
135	  return { payout, remainingCap: cap - payout };
136	};
137	
138	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
139	  results: scenario.steps.map((step, i) =>
140	    step.op === "quote"
141	      ? priceQuote(step, scenario.customer, countQuotesBefore(scenario.steps, i) > 0)
142	      : processClaim(step, scenario.steps),
143	  ),
144	});
